root = 'C:/Users/016551/OneDrive/Desktop/IWE'
review_re = re.compile(r'(temp|tmp|cache|cursor_excel|synced|sync|intermediate|output|draft|backup|bak|~\$|\.tmp$|\.temp$|\.bak$|\.log$)', re.I)
def fmt(n):
    n = int(n)
    if n >= 1024**3: return f'{n/(1024**3):.2f} GB'
    if n >= 1024**2: return f'{n/(1024**2):.2f} MB'
    if n >= 1024: return f'{n/1024:.2f} KB'
    return f'{n} B'
def mtime(path):
    return datetime.datetime.fromtimestamp(os.path.getmtime(path)).strftime('%Y-%m-%d %H:%M:%S')
def dir_size(path):
    total = 0
    for dp, dns, fns in os.walk(path):
        for fn in fns:
            fp = os.path.join(dp, fn)
            try: total += os.path.getsize(fp)
            except OSError: pass
    return total
def flag(name):
