        dns.sort(key=str.lower); fns.sort(key=str.lower)
        rel = os.path.relpath(dp, root)
        depth = 0 if rel == '.' else rel.count(os.sep) + 1
        for dn in dns:
            p = os.path.join(dp, dn)
